import { useState } from "react";

const API = "http://127.0.0.1:8000";

function BMI({ token, onLogout }) {
  const [form, setForm] = useState({ age: "", weight: "", height: "" });
  const [bmiResult, setBmiResult] = useState(null);
  const [goalForm, setGoalForm] = useState({ target_bmi: "", timeline_weeks: "" });
  const [goalResult, setGoalResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [goalLoading, setGoalLoading] = useState(false);
  const [error, setError] = useState("");

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });
  const handleGoalChange = (e) => setGoalForm({ ...goalForm, [e.target.name]: e.target.value });

  const handleCalculateBMI = async () => {
    setLoading(true);
    setError("");
    setBmiResult(null);
    setGoalResult(null);
    try {
      const res = await fetch(`${API}/bmi`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({
          age: parseInt(form.age),
          weight: parseFloat(form.weight),
          height: parseFloat(form.height),
        }),
      });
      const data = await res.json();
      if (res.ok) setBmiResult(data);
      else setError("❌ " + data.detail);
    } catch {
      setError("❌ Server error");
    }
    setLoading(false);
  };

  const handleCalculateGoal = async () => {
    setGoalLoading(true);
    setError("");
    try {
      const res = await fetch(`${API}/goal`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({
          age: parseInt(form.age),
          weight: parseFloat(form.weight),
          height: parseFloat(form.height),
          target_bmi: parseFloat(goalForm.target_bmi),
          timeline_weeks: parseInt(goalForm.timeline_weeks),
        }),
      });
      const data = await res.json();
      if (res.ok) setGoalResult(data);
      else setError("❌ " + data.detail);
    } catch {
      setError("❌ Server error");
    }
    setGoalLoading(false);
  };

  const getCategoryColor = (category) => {
    if (category === "Underweight") return "#60a5fa";
    if (category === "Normal weight") return "#4ade80";
    if (category === "Overweight") return "#facc15";
    return "#f87171";
  };

  return (
    <div style={styles.wrapper}>
      <div style={styles.card}>

        {/* Header */}
        <div style={styles.header}>
          <h1 style={styles.title}>🧮 BMI Calculator</h1>
          <button style={styles.logout} onClick={onLogout}>Logout</button>
        </div>

        {/* BMI Form */}
        <div style={styles.form}>
          <input style={styles.input} type="number" name="age"
            placeholder="Age (years)" value={form.age} onChange={handleChange} />
          <input style={styles.input} type="number" name="weight"
            placeholder="Weight (kg)" value={form.weight} onChange={handleChange} />
          <input style={styles.input} type="number" name="height"
            placeholder="Height (cm)" value={form.height} onChange={handleChange} />
          {error && <p style={styles.error}>{error}</p>}
          <button style={styles.button} onClick={handleCalculateBMI} disabled={loading}>
            {loading ? "Calculating..." : "Calculate BMI"}
          </button>
        </div>

        {/* BMI Result */}
        {bmiResult && (
          <div style={styles.resultBox}>
            <p style={styles.bmiValue}>{bmiResult.bmi}</p>
            <p style={{ ...styles.category, color: getCategoryColor(bmiResult.category) }}>
              {bmiResult.category}
            </p>
            <p style={styles.subtext}>Age: {bmiResult.age} years</p>
          </div>
        )}

        {/* Goal Form */}
        {bmiResult && (
          <div style={styles.goalSection}>
            <h2 style={styles.goalTitle}>🎯 Set Your Goal</h2>
            <p style={styles.subtext}>Current BMI: <b>{bmiResult.bmi}</b> — Enter your target BMI and timeline</p>
            <div style={styles.form}>
              <input style={styles.input} type="number" name="target_bmi"
                placeholder="Target BMI (e.g. 22)" value={goalForm.target_bmi} onChange={handleGoalChange} />
              <input style={styles.input} type="number" name="timeline_weeks"
                placeholder="Timeline in weeks (e.g. 12)" value={goalForm.timeline_weeks} onChange={handleGoalChange} />
              <button style={styles.button} onClick={handleCalculateGoal} disabled={goalLoading}>
                {goalLoading ? "AI is calculating..." : "Get My Plan"}
              </button>
            </div>
          </div>
        )}

        {/* Goal Result */}
        {goalResult && (
          <div style={styles.goalResult}>
            <h2 style={styles.goalTitle}>📊 Your Plan</h2>

            <div style={styles.statsRow}>
              <div style={styles.statBox}>
                <p style={styles.statValue}>{goalResult.daily_calories}</p>
                <p style={styles.statLabel}>Daily Calories</p>
              </div>
              <div style={styles.statBox}>
                <p style={styles.statValue}>{goalResult.target_weight} kg</p>
                <p style={styles.statLabel}>Target Weight</p>
              </div>
              <div style={styles.statBox}>
                <p style={{ ...styles.statValue, color: goalResult.weight_change > 0 ? "#4ade80" : "#f87171" }}>
                  {goalResult.weight_change > 0 ? "+" : ""}{goalResult.weight_change} kg
                </p>
                <p style={styles.statLabel}>Weight Change</p>
              </div>
            </div>

            <div style={styles.infoRow}>
              <span style={styles.badge}>⚡ {goalResult.deficit_surplus}</span>
              <span style={{ ...styles.badge, background: goalResult.realistic === "Yes" ? "#166534" : "#7f1d1d" }}>
                {goalResult.realistic === "Yes" ? "✅ Realistic Goal" : "⚠️ Challenging Goal"}
              </span>
            </div>

            <div style={styles.adviceBox}>
              <p style={styles.adviceText}>💡 {goalResult.advice}</p>
            </div>
          </div>
        )}

      </div>
    </div>
  );
}

const styles = {
  wrapper: {
    minHeight: "100vh",
    background: "#0f0f0f",
    display: "flex",
    justifyContent: "center",
    alignItems: "flex-start",
    padding: "40px 16px",
  },
  card: {
    background: "#1a1a1a",
    padding: "40px",
    borderRadius: "16px",
    width: "100%",
    maxWidth: "480px",
    boxShadow: "0 0 30px rgba(0,0,0,0.5)",
  },
  header: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    marginBottom: "24px",
  },
  title: { fontSize: "22px", color: "#4ade80" },
  logout: {
    background: "transparent",
    border: "1px solid #444",
    color: "#aaa",
    padding: "6px 12px",
    borderRadius: "6px",
    fontSize: "13px",
  },
  form: { display: "flex", flexDirection: "column", gap: "14px" },
